+    #[test]
+    fn from_rng() {
+        let mut rng = DetRng::new(42);
+        let ctx1 = SecurityContext::from_rng(&mut rng);
+        let ctx2 = SecurityContext::from_rng(&mut rng);
+
+        // Different keys from same RNG stream
+        assert_ne!(ctx1.key(), ctx2.key());
